use xcap::Monitor;
use image::ImageFormat;
use std::path::PathBuf;
use chrono::Local;

pub async fn capture_primary_monitor(output_dir: &PathBuf) -> Result<PathBuf, CaptureError> {
    let start = std::time::Instant::now();

    // プライマリモニタを取得
    let monitors = Monitor::all()?;
    let primary = monitors.iter()
        .find(|m| m.is_primary())
        .ok_or(CaptureError::NoPrimaryMonitor)?;

    // スクリーンショット取得
    let image = primary.capture_image()?;

    // タイムスタンプベースのファイル名
    let timestamp = Local::now().format("%Y%m%d_%H%M%S");
    let filename = format!("screenshot_{}.png", timestamp);
    let path = output_dir.join(&filename);

    // PNG として保存
    image.save_with_format(&path, ImageFormat::Png)?;

    // パフォーマンス確認（500ms以内）
    let elapsed = start.elapsed();
    if elapsed > std::time::Duration::from_millis(500) {
        log::warn!("Screenshot took too long: {:?}", elapsed);
    }

    Ok(path)
}
```
