use windows::Win32::UI::WindowsAndMessaging::{
    GetForegroundWindow, GetWindowTextW, GetWindowThreadProcessId
};
use windows::Win32::System::ProcessStatus::GetModuleBaseNameW;
use windows::Win32::Foundation::HWND;
use std::ffi::OsString;
use std::os::windows::ffi::OsStringExt;

#[derive(Debug, Clone, serde::Serialize)]
pub struct WindowMetadata {
    pub window_title: String,
    pub process_name: String,
    pub process_id: u32,
}

pub fn get_active_window_metadata() -> Result<WindowMetadata, WindowMetaError> {
    unsafe {
        let hwnd = GetForegroundWindow();
        if hwnd.0 == 0 {
            return Err(WindowMetaError::NoActiveWindow);
        }

        // ウィンドウタイトル取得
        let mut title_buf = vec![0u16; 512];
        let title_len = GetWindowTextW(hwnd, &mut title_buf);
        let window_title = OsString::from_wide(&title_buf[..title_len as usize])
            .to_string_lossy()
            .to_string();

        // プロセスID取得
        let mut pid: u32 = 0;
        GetWindowThreadProcessId(hwnd, Some(&mut pid));

        // プロセス名取得
        let process_name = get_process_name(pid)?;

        Ok(WindowMetadata { window_title, process_name, process_id: pid })
    }
}
```
