use tokio::time::{interval, Duration};
use tokio::sync::watch;
use crate::state::AppState;

pub async fn recording_loop(
    state: AppState,
    mut stop_rx: watch::Receiver<bool>,
) {
    let config = state.config.lock().await.clone();
    let mut ticker = interval(Duration::from_secs(config.capture_interval_secs));
    let mut prev_hash: Option<u64> = None;

    loop {
        tokio::select! {
            _ = ticker.tick() => {
                if *stop_rx.borrow() { break; }

                // スクリーンショット取得
                let image_path = match capture_primary_monitor(&data_dir).await {
                    Ok(p) => p,
                    Err(e) => { log::error!("Capture failed: {:?}", e); continue; }
                };

                // 画像ロードして差分チェック
                let img = image::open(&image_path).unwrap();
                let hash = compute_dhash(&img);

                if let Some(ph) = prev_hash {
                    let config = state.config.lock().await;
                    if !has_significant_change(ph, hash, config.dhash_threshold) {
                        // 変化なし: 画像削除してスキップ
                        let _ = std::fs::remove_file(&image_path);
                        continue;
                    }
                }
                prev_hash = Some(hash);

                // メタデータ取得
                let meta = get_active_window_metadata().unwrap_or_default();

                // CaptureRecord を保存
                save_capture_record(&state, &image_path, &meta, hash).await;
            }
            _ = stop_rx.changed() => {
                if *stop_rx.borrow() { break; }
            }
        }
    }
}
```
