use rusqlite::{Connection, params};

pub fn initialize_db(db_path: &str) -> Result<Connection, rusqlite::Error> {
    let conn = Connection::open(db_path)?;
    conn.execute_batch("
        CREATE TABLE IF NOT EXISTS captures (
            id TEXT PRIMARY KEY,
            timestamp TEXT NOT NULL,
            app TEXT NOT NULL,
            window_title TEXT NOT NULL,
            image_path TEXT,
            dhash TEXT,
            description TEXT,
            vlm_processed INTEGER DEFAULT 0,
            created_at TEXT DEFAULT CURRENT_TIMESTAMP
        );
        CREATE INDEX IF NOT EXISTS idx_timestamp ON captures(timestamp);
        CREATE INDEX IF NOT EXISTS idx_app ON captures(app);
        CREATE INDEX IF NOT EXISTS idx_vlm_processed ON captures(vlm_processed);
    ")?;
    Ok(conn)
}

pub fn insert_capture(conn: &Connection, record: &CaptureRecord) -> Result<(), rusqlite::Error> {
    conn.execute(
        "INSERT INTO captures (id, timestamp, app, window_title, image_path, dhash) VALUES (?1, ?2, ?3, ?4, ?5, ?6)",
        params![record.id, record.timestamp, record.app, record.window_title, record.image_path, record.dhash]
    )?;
    Ok(())
}
