use std::process::{Child, Command, Stdio};
use reqwest::Client;

pub struct LlamaServer {
    process: Option<Child>,
    host: String,
    port: u16,
    client: Client,
}

impl LlamaServer {
    pub async fn start(
        &mut self,
        model_path: &str,
        mmproj_path: &str,
        n_threads: usize,
    ) -> Result<(), VlmError> {
        let child = Command::new("llama-server")
            .args([
                "-m", model_path,
                "--mmproj", mmproj_path,
                "--host", &self.host,
                "--port", &self.port.to_string(),
                "-t", &n_threads.to_string(),
                "--ctx-size", "4096",
                "--log-disable",
            ])
            .stdout(Stdio::null())
            .stderr(Stdio::null())
            .spawn()?;

        self.process = Some(child);
        self.wait_for_ready(30).await?; // 最大30秒待機
        Ok(())
    }

    pub async fn wait_for_ready(&self, timeout_secs: u64) -> Result<(), VlmError> {
        let deadline = std::time::Instant::now() + std::time::Duration::from_secs(timeout_secs);
        loop {
            if std::time::Instant::now() > deadline {
                return Err(VlmError::StartupTimeout);
            }
            match self.client.get(format!("http://{}:{}/health", self.host, self.port)).send().await {
                Ok(r) if r.status().is_success() => return Ok(()),
                _ => tokio::time::sleep(std::time::Duration::from_millis(500)).await,
            }
        }
    }

    pub fn stop(&mut self) {
        if let Some(mut child) = self.process.take() {
            let _ = child.kill();
        }
    }
}
```
