use reqwest::Client;
use base64::{Engine as _, engine::general_purpose::STANDARD as BASE64};
use std::path::Path;

const SYSTEM_PROMPT: &str = "あなたは業務PC画面の分析アシスタントです。\
    スクリーンショットを見て、実行中の業務と操作内容を日本語で簡潔に記述してください。\
    アプリケーション名、操作内容、表示データの種類を含めてください。";

const USER_PROMPT: &str = "この画面スクリーンショットに写っている業務操作を説明してください。\
    1-3文で簡潔に記述してください。";

pub async fn describe_screenshot(
    client: &Client,
    image_path: &Path,
    server_url: &str,
    max_tokens: u32,
) -> Result<String, VlmError> {
    // 画像を base64 エンコード
    let image_bytes = tokio::fs::read(image_path).await?;
    let image_b64 = BASE64.encode(&image_bytes);

    // OpenAI 互換マルチモーダルリクエスト
    let payload = serde_json::json!({
        "model": "qwen",
        "messages": [{
            "role": "system",
            "content": SYSTEM_PROMPT
        }, {
            "role": "user",
            "content": [{
                "type": "image_url",
                "image_url": {
                    "url": format!("data:image/png;base64,{}", image_b64)
                }
            }, {
                "type": "text",
                "text": USER_PROMPT
            }]
        }],
        "max_tokens": max_tokens,
        "temperature": 0.1
    });

    let response = client
        .post(format!("{}/v1/chat/completions", server_url))
        .json(&payload)
        .timeout(std::time::Duration::from_secs(60))
        .send()
        .await?
        .json::<serde_json::Value>()
        .await?;

    let text = response["choices"][0]["message"]["content"]
        .as_str()
        .unwrap_or("[記述生成失敗]")
        .to_string();

    Ok(text)
}
```
