```rust
use tauri::{AppHandle, Emitter};

#[derive(Clone, serde::Serialize)]
struct BatchProgress {
    total: usize,
    completed: usize,
    failed: usize,
    current_id: Option<String>,
    estimated_remaining_secs: Option<u64>,
}

pub async fn run_vlm_batch(
    app: AppHandle,
    state: AppState,
    auto_delete: bool,
) -> Result<BatchResult, VlmError> {
    let unprocessed = get_unprocessed_captures(&state.db).await?;
    let total = unprocessed.len();

    let mut completed = 0;
    let mut failed = 0;
    let mut elapsed_times: Vec<u64> = vec![];

    for record in &unprocessed {
        // 進捗通知
        let avg_time = if elapsed_times.is_empty() { 30u64 }
            else { elapsed_times.iter().sum::<u64>() / elapsed_times.len() as u64 };

        let _ = app.emit("vlm-progress", BatchProgress {
            total,
            completed,
            failed,
            current_id: Some(record.id.clone()),
            estimated_remaining_secs: Some(avg_time * (total - completed) as u64),
        });

        let start = std::time::Instant::now();

        match describe_screenshot(
            &state.vlm_client,
            &record.image_path,
            &state.config.vlm_host,
            state.config.vlm_max_tokens,
        ).await {
            Ok(description) => {
                update_description(&state.db, &record.id, &description).await?;
                if auto_delete {
                    let _ = tokio::fs::remove_file(&record.image_path).await;
                }
                elapsed_times.push(start.elapsed().as_secs());
                completed += 1;
            }
            Err(e) => {
                log::error!("VLM inference failed for {}: {:?}", record.id, e);
                failed += 1;
            }
        }
    }

    Ok(BatchResult { total, completed, failed })
}
```
