use csv::Writer;
use std::io::Write;

#[derive(serde::Deserialize)]
pub struct ExportFilter {
    pub start_date: Option<String>, // YYYY-MM-DD
    pub end_date: Option<String>,   // YYYY-MM-DD
    pub apps: Option<Vec<String>>,  // アプリ名フィルタ
    pub only_processed: bool,       // VLM処理済みのみ
}

pub async fn export_to_csv(
    conn: &Connection,
    filter: &ExportFilter,
    output_path: &str,
) -> Result<usize, ExportError> {
    // UTF-8 BOM を先頭に書き込み（Excel対応）
    let mut file = std::fs::File::create(output_path)?;
    file.write_all(&[0xEF, 0xBB, 0xBF])?; // BOM

    let mut writer = Writer::from_writer(file);

    // ヘッダー行
    writer.write_record(&["timestamp", "app", "window_title", "description"])?;

    // DBからフィルタリングしてデータ取得
    let records = query_captures_filtered(conn, filter)?;
    let count = records.len();

    for record in records {
        writer.write_record(&[
            &record.timestamp,
            &record.app,
            &record.window_title,
            &record.description.unwrap_or_default(),
        ])?;
    }

    writer.flush()?;
    Ok(count)
}
```
