pub fn setup_tray(app: &AppHandle) -> Result<(), tauri::Error> {
    let menu = tauri::menu::MenuBuilder::new(app)
        .item(&tauri::menu::MenuItem::with_id(app, "show", "ウィンドウを表示", true, None::<&str>)?)
        .separator()
        .item(&tauri::menu::MenuItem::with_id(app, "start_recording", "記録開始", true, None::<&str>)?)
