```rust
use tokio::time::{sleep_until, Instant};
use chrono::{Local, NaiveTime, Timelike};

pub async fn batch_scheduler_loop(
    app: AppHandle,
    state: AppState,
    mut config_rx: watch::Receiver<AppConfig>,
) {
    loop {
        let config = config_rx.borrow().clone();
        let batch_time = NaiveTime::parse_from_str(&config.batch_time, "%H:%M")
            .unwrap_or(NaiveTime::from_hms_opt(22, 0, 0).unwrap());

        // 次回実行時刻を計算
        let now = Local::now();
        let mut next_run = now.date_naive().and_time(batch_time);
        if next_run <= now.naive_local() {
            next_run = next_run + chrono::Duration::days(1);
        }

        let duration = (next_run - now.naive_local()).to_std().unwrap();

        tokio::select! {
            _ = tokio::time::sleep(duration) => {
                // 未処理件数をチェック
                let unprocessed_count = count_unprocessed(&state.db).await.unwrap_or(0);
                if unprocessed_count > 0 {
                    log::info!("Starting scheduled VLM batch: {} items", unprocessed_count);
                    // llama-server 起動
                    let _ = start_vlm_server(&state).await;
                    // バッチ実行
                    let _ = run_vlm_batch(app.clone(), state.clone(), true).await;
                    // llama-server 停止
                    let _ = stop_vlm_server(&state).await;
                }
            }
            _ = config_rx.changed() => {
                // 設定変更時はスケジュールを再計算
                continue;
            }
        }
    }
}
```
